mapper.update:
update members
set last_login_at = CONVERT_TZ(NOW(6), '+00:00', '+09:00')
where member_id = #{memberId}

mapper.select:
SELECT m.member_id as userId, coalesce(m.nickname, m.name) as nickname, m.profile_image_url as profileImage FROM follow_tbl f JOIN members m ON f.following_member_id = m.member_id WHERE f.follower_member_id = #{memberId}
AND LOWER(COALESCE(m.nickname, m.name)) LIKE CONCAT('%', LOWER(#{keyword}), '%')
ORDER BY f.created_at DESC
